mapper.select:
SELECT cs.id, cs.student_id as studentId, cs.student_no as studentId, cs.student_name as name, cs.learning_progress as learningProgress, cs.average_score as score, cs.last_login_time as lastLogin, cs.join_time as joinTime FROM class_student cs WHERE cs.deleted = 0 AND cs.class_id = #{classId}
AND (cs.student_name LIKE CONCAT('%', #{keyword}, '%') OR cs.student_no LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY cs.join_time DESC
